window.QUESTIONS_D2 = [
{"id":"RW-D2-05","domain":1,"cog":"AP","correct":"A","task":"Task 2.2","stem":"A lab interface sends &quot;serum sodium&quot; from one facility and &quot;Na blood&quot; from another. The analytics team needs consistent reporting across sites. Which standard is MOST relevant?","opts":[{"l":"A","c":true,"t":"LOINC"},{"l":"B","c":false,"t":"CPT"},{"l":"C","c":false,"t":"ICD-10-PCS"},{"l":"D","c":false,"t":"DICOM"}],"rat":"LOINC standardizes laboratory test names and clinical observations, enabling semantic interoperability across systems."},
{"id":"RW-D2-06","domain":1,"cog":"AP","correct":"A","task":"Task 2.2","stem":"A medication list combines drug data from the EHR, pharmacy claims, and a patient app. Which terminology helps normalize medication names and clinical drug concepts across these sources?","opts":[{"l":"A","c":true,"t":"RxNorm"},{"l":"B","c":false,"t":"DRG"},{"l":"C","c":false,"t":"SNOMED CT only"},{"l":"D","c":false,"t":"CPT"}],"rat":"RxNorm provides normalized clinical drug names and relationships; it enables drug data from disparate systems to be mapped to a common representation."},
{"id":"RW-D2-12","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A hospital coder is assigning procedure codes for a patient who had a laparoscopic appendectomy performed during an inpatient admission. Which coding system is correct for the procedure?","opts":[{"l":"A","c":false,"t":"CPT"},{"l":"B","c":false,"t":"HCPCS Level II"},{"l":"C","c":true,"t":"ICD-10-PCS"},{"l":"D","c":false,"t":"ICD-10-CM"}],"rat":"ICD-10-PCS is used for inpatient procedure coding; CPT is used for outpatient and physician service billing. ICD-10-CM codes diagnoses, not procedures."},
{"id":"RW-D2-15","domain":1,"cog":"RE","correct":"C","task":"Task 2.2","stem":"A patient is discharged and requires a motorized wheelchair for home use. The appropriate code set for billing Medicare is:","opts":[{"l":"A","c":false,"t":"CPT"},{"l":"B","c":false,"t":"ICD-10-CM"},{"l":"C","c":true,"t":"HCPCS Level II"},{"l":"D","c":false,"t":"NDC"}],"rat":"HCPCS Level II covers durable medical equipment, supplies, and drugs not covered by standard CPT codes."},
{"id":"RW-D2-18","domain":1,"cog":"AN","correct":"B","task":"Task 2.2","stem":"A large multi-specialty practice wants to share longitudinal patient records with outside specialists and the regional hospital. An EMR is inadequate for this goal primarily because:","opts":[{"l":"A","c":false,"t":"EMRs cannot support CPOE"},{"l":"B","c":true,"t":"EMRs are not designed for interoperability and sharing across organizations"},{"l":"C","c":false,"t":"EMRs do not support billing codes"},{"l":"D","c":false,"t":"EHRs are less expensive than EMRs"}],"rat":"EMRs serve a single provider and are not designed for external sharing; EHRs are built specifically to support coordinated care across multiple organizations."},
{"id":"RW-D2-19","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A hospital&#x27;s eligible professionals want to receive CMS incentive payments for demonstrating specific health IT use, including providing patients electronic access to their health records. This program is currently known as:","opts":[{"l":"A","c":false,"t":"Meaningful Use Stage 1"},{"l":"B","c":false,"t":"Health Information Exchange Certification"},{"l":"C","c":true,"t":"Promoting Interoperability (PI)"},{"l":"D","c":false,"t":"ONC Cures Act Certification"}],"rat":"CMS renamed the Meaningful Use program to Promoting Interoperability; it offers Medicare/Medicaid incentive payments for demonstrated health IT use across three progressive stages."},
{"id":"RW-D2-26","domain":1,"cog":"AN","correct":"B","task":"Task 2.2","stem":"A clinical analytics team receives lab data where one system uses &quot;SNOMED CT&quot; to document the clinical concept &quot;hypertension&quot; and another uses &quot;LOINC&quot; to report blood pressure measurement results. Which statement BEST distinguishes these two standards?","opts":[{"l":"A","c":false,"t":"SNOMED CT and LOINC can be used interchangeably for lab results"},{"l":"B","c":true,"t":"SNOMED CT codes clinical concepts and findings in EHR documentation; LOINC codes laboratory tests and observable measurements"},{"l":"C","c":false,"t":"LOINC is for diagnoses; SNOMED CT is for drug names"},{"l":"D","c":false,"t":"Both standards are required only for inpatient billing"}],"rat":"SNOMED CT provides a comprehensive clinical terminology for EHR concepts (diagnoses, procedures, findings); LOINC standardizes laboratory tests and clinical observations for exchange."},
{"id":"RW-D2-27","domain":1,"cog":"RE","correct":"C","task":"Task 2.2","stem":"A pharmacist needs to identify the exact manufacturer, product, and package size of a medication involved in a dispensing error. Which code uniquely identifies a specific drug product at the package level?","opts":[{"l":"A","c":false,"t":"RxNorm"},{"l":"B","c":false,"t":"HCPCS Level II"},{"l":"C","c":true,"t":"NDC (National Drug Code)"},{"l":"D","c":false,"t":"LOINC"}],"rat":"NDC is a product-level identifier that includes manufacturer, drug product, and package size. RxNorm normalizes clinical drug concepts but does not identify specific commercial packages."},
{"id":"RW-D2-04","domain":1,"cog":"AN","correct":"B","task":"Task 2.3, 2.4","stem":"BCMA compliance drops from 96% to 84% on the night shift. Nurses report that barcode labels on refrigerated medications often smudge. What is the BEST next step?","opts":[{"l":"A","c":false,"t":"Discipline the night shift nurses"},{"l":"B","c":true,"t":"Observe the workflow and correct the labeling/process defect"},{"l":"C","c":false,"t":"Turn off BCMA for refrigerated medications"},{"l":"D","c":false,"t":"Require nurses to manually type every NDC"}],"rat":"The data points to a process and usability defect. Fix the root cause before assuming noncompliance."},
{"id":"RW-D2-13","domain":1,"cog":"AP","correct":"B","task":"Task 2.3","stem":"A 250-bed hospital reports 6,750 total inpatient patient days in September (30-day month). What is the Average Daily Census?","opts":[{"l":"A","c":false,"t":"250"},{"l":"B","c":true,"t":"225"},{"l":"C","c":false,"t":"6,750"},{"l":"D","c":false,"t":"27"}],"rat":"ADC = total patient days ÷ number of days in the period = 6,750 ÷ 30 = 225. Bed occupancy rate = 225/250 = 90%."},
{"id":"RW-D2-14","domain":1,"cog":"AN","correct":"C","task":"Task 2.3","stem":"A hospital&#x27;s Case Mix Index dropped from 1.85 to 1.62 after a specialty surgical center opened nearby and captured complex elective cases. The MOST likely financial consequence is:","opts":[{"l":"A","c":false,"t":"Increased average length of stay"},{"l":"B","c":false,"t":"Increased per-case DRG reimbursement"},{"l":"C","c":true,"t":"Decreased per-case reimbursement because the remaining cases are clinically less complex"},{"l":"D","c":false,"t":"Improved quality scores from reduced complexity"}],"rat":"CMI reflects the average DRG weight. A lower CMI = lower complexity = lower reimbursement per discharge under DRG-based payment."},
{"id":"RW-D2-28","domain":1,"cog":"AP","correct":"B","task":"Task 2.3","stem":"A 300-bed hospital has an Average Daily Census of 255. What is the bed occupancy rate?","opts":[{"l":"A","c":false,"t":"45%"},{"l":"B","c":true,"t":"85%"},{"l":"C","c":false,"t":"115%"},{"l":"D","c":false,"t":"300%"}],"rat":"Bed occupancy rate = (ADC ÷ Licensed beds) × 100 = (255 ÷ 300) × 100 = 85%."},
{"id":"RW-D2-29","domain":1,"cog":"AP","correct":"B","task":"Task 2.3","stem":"A hospitalist quality program tracks the percentage of patients who are readmitted within 30 days of a heart failure discharge. This metric is BEST described as:","opts":[{"l":"A","c":false,"t":"Average Length of Stay"},{"l":"B","c":true,"t":"30-day all-cause readmission rate"},{"l":"C","c":false,"t":"Case Mix Index"},{"l":"D","c":false,"t":"Bed turnover rate"}],"rat":"30-day readmission rate = (patients readmitted within 30 days ÷ total discharges) × 100. It is a key CMS quality and payment metric for heart failure."},
{"id":"RW-D2-22","domain":1,"cog":"AP","correct":"B","task":"Task 2.3, 2.4","stem":"During a BCMA audit, a nurse is found to have scanned the patient wristband but not the medication barcode, relying on visual identification of the medication package. Which of the Five Rights is MOST at risk?","opts":[{"l":"A","c":false,"t":"Right patient"},{"l":"B","c":true,"t":"Right drug"},{"l":"C","c":false,"t":"Right time"},{"l":"D","c":false,"t":"Right route"}],"rat":"Scanning the medication barcode is the system-level check that verifies the Right Drug. Skipping it removes the automated safeguard against wrong-drug errors."},
{"id":"RW-D2-01","domain":1,"cog":"AP","correct":"A","task":"Task 2.4, 2.6","stem":"During medication ordering, an alert fires because a patient with a documented penicillin allergy is prescribed amoxicillin. What safety function is being demonstrated?","opts":[{"l":"A","c":true,"t":"Drug-allergy clinical decision support"},{"l":"B","c":false,"t":"Charge capture"},{"l":"C","c":false,"t":"Diagnostic coding"},{"l":"D","c":false,"t":"Query-based HIE"}],"rat":"The system is checking a medication order against the patient&#x27;s documented allergy at the point of clinical decision-making — a core CDS safety function."},
{"id":"RW-D2-10","domain":1,"cog":"AP","correct":"B","task":"Task 2.3, 2.4","stem":"A nurse scans the patient wristband and the medication package, then documents whether the medication was given or refused. Which system functionality is central to this workflow?","opts":[{"l":"A","c":false,"t":"CPOE only"},{"l":"B","c":true,"t":"eMAR integrated with BCMA"},{"l":"C","c":false,"t":"PACS"},{"l":"D","c":false,"t":"Revenue cycle claims adjudication"}],"rat":"eMAR documents medication administration; BCMA verifies the five rights (patient, drug, dose, route, time) at the bedside via barcode scanning."},
{"id":"RW-D2-20","domain":1,"cog":"AN","correct":"B","task":"Task 2.4","stem":"An orthopedic unit has highly variable post-operative nursing assessments — some nurses document in paragraphs, others use bullet points — making quality metric extraction impossible. The best long-term informatics solution is:","opts":[{"l":"A","c":false,"t":"Require all nurses to use the same paragraph template"},{"l":"B","c":true,"t":"Redesign the assessment using structured data fields with validated clinical terminology"},{"l":"C","c":false,"t":"Export all free-text monthly for manual review"},{"l":"D","c":false,"t":"Reduce the number of required assessment elements"}],"rat":"Structured data entry using standardized terminology enables consistent documentation, automated quality reporting, and analytics — free-text alone cannot reliably support metric extraction."},
{"id":"RW-D2-07","domain":1,"cog":"AN","correct":"D","task":"Task 2.5","stem":"A care management platform calculates a 90-day readmission risk score and automatically routes high-risk patients to a nurse outreach queue. What analytics maturity level does the automatic routing represent?","opts":[{"l":"A","c":false,"t":"Descriptive"},{"l":"B","c":false,"t":"Diagnostic"},{"l":"C","c":false,"t":"Predictive only"},{"l":"D","c":true,"t":"Prescriptive"}],"rat":"Calculating the risk score is predictive; automatically triggering an action (routing to a care queue) based on that prediction is prescriptive analytics."},
{"id":"RW-D2-08","domain":1,"cog":"AP","correct":"B","task":"Task 2.5","stem":"The CMO asks whether average length of stay increased after a new discharge workflow. Which visualization is MOST useful to see the monthly trend and detect a potential process change over time?","opts":[{"l":"A","c":false,"t":"Pie chart"},{"l":"B","c":true,"t":"Run chart or control chart"},{"l":"C","c":false,"t":"Single KPI snapshot"},{"l":"D","c":false,"t":"Organization chart"}],"rat":"Trends and process variation over time are best assessed with run charts (simple trend) or control charts (statistical process control with upper/lower control limits)."},
{"id":"RW-D2-09","domain":1,"cog":"AN","correct":"B","task":"Task 2.5","stem":"A dashboard shows that readmissions rose after a new care management workflow. A committee member says, &quot;This proves the workflow caused the increase.&quot; What is the BEST response?","opts":[{"l":"A","c":false,"t":"Agree, because the timing proves causation"},{"l":"B","c":true,"t":"Explain that the data shows correlation and recommend further analysis for causation"},{"l":"C","c":false,"t":"Remove the dashboard metric"},{"l":"D","c":false,"t":"Stop all care management activity immediately"}],"rat":"Observational trend data can suggest an association but does not prove causation; rigorous analysis (controlling for confounders) is required before attributing causality."},
{"id":"RW-D2-16","domain":1,"cog":"AN","correct":"C","task":"Task 2.5","stem":"A hospital quality team wants to automatically identify patients with documented hypertension, diabetes, and chronic kidney disease from physician progress notes to populate a disease registry. Which technology is MOST applicable?","opts":[{"l":"A","c":false,"t":"BCMA scanning"},{"l":"B","c":false,"t":"HL7 ADT messaging"},{"l":"C","c":true,"t":"Natural Language Processing (NLP)"},{"l":"D","c":false,"t":"DICOM image parsing"}],"rat":"NLP extracts structured clinical concepts (diagnoses, findings, medications) from unstructured free-text clinical notes, enabling automated registry population."},
{"id":"RW-D2-21","domain":1,"cog":"AP","correct":"B","task":"Task 2.5","stem":"The quality team reports sepsis mortality increased 12% last quarter. The CMO asks: &quot;What changed in our care processes or patient population that drove this increase?&quot; This question calls for:","opts":[{"l":"A","c":false,"t":"Descriptive analytics"},{"l":"B","c":true,"t":"Diagnostic analytics"},{"l":"C","c":false,"t":"Predictive analytics"},{"l":"D","c":false,"t":"Prescriptive analytics"}],"rat":"Diagnostic analytics investigates the root cause or explanation behind an observed outcome — answering why something happened."},
{"id":"RW-D2-30","domain":1,"cog":"AP","correct":"C","task":"Task 2.5","stem":"An informatics team presents a report showing the hospital&#x27;s ALOS of 5.4 days against a national benchmark of 4.6 days for similar case mix. The team is using:","opts":[{"l":"A","c":false,"t":"Descriptive analytics only"},{"l":"B","c":false,"t":"Diagnostic analytics"},{"l":"C","c":true,"t":"Benchmarking for comparative performance analysis"},{"l":"D","c":false,"t":"Prescriptive analytics"}],"rat":"Benchmarking compares organizational performance against an external reference (national average, peer group) to identify gaps and set improvement targets."},
{"id":"RW-D2-31","domain":1,"cog":"AP","correct":"C","task":"Task 2.5","stem":"An infection control team wants to determine whether there is a statistical relationship between nurse-to-patient ratios and CLABSI rates across 12 units. Which visualization best reveals this relationship?","opts":[{"l":"A","c":false,"t":"Bar chart comparing CLABSI rates by unit"},{"l":"B","c":false,"t":"Run chart of monthly CLABSI rates"},{"l":"C","c":true,"t":"Scatter plot of staffing ratios versus CLABSI rates"},{"l":"D","c":false,"t":"Pie chart of infection type proportions"}],"rat":"Scatter plots reveal the correlation (or lack thereof) between two continuous variables — ideal for exploring whether one factor is related to another."},
{"id":"RW-D2-32","domain":1,"cog":"AN","correct":"B","task":"Task 2.5","stem":"A study reports that a new medication reconciliation workflow reduced 30-day readmissions by 18% (p = 0.03). A committee member asks what the p-value means. The BEST explanation is:","opts":[{"l":"A","c":false,"t":"The study found the intervention reduced readmissions by exactly 3%"},{"l":"B","c":true,"t":"There is a 3% probability this result occurred by chance alone, meaning it is statistically significant"},{"l":"C","c":false,"t":"The study only found results in 3 of the 10 participating hospitals"},{"l":"D","c":false,"t":"The confidence interval was 3% wide"}],"rat":"A p-value of 0.03 means there is a 3% probability the observed result was due to random chance; by convention, p &lt; 0.05 is considered statistically significant."},
{"id":"RW-D2-02","domain":1,"cog":"AN","correct":"B","task":"Task 2.6","stem":"A hospital finds that 94% of a low-severity drug interaction alert is overridden. Physicians say the alert fires for clinically insignificant combinations. What should the CDS committee do FIRST?","opts":[{"l":"A","c":false,"t":"Convert the alert to a hard stop"},{"l":"B","c":true,"t":"Analyze override reasons and retune or retire the alert if it is low value"},{"l":"C","c":false,"t":"Add more alerts to improve awareness"},{"l":"D","c":false,"t":"Disable all medication alerts for two weeks"}],"rat":"A 94% override rate signals alert fatigue. The CDS governance committee should first evaluate clinical value — then either retune or retire the alert, not escalate its severity."},
{"id":"RW-D2-03","domain":1,"cog":"AP","correct":"C","task":"Task 2.6","stem":"A quality team wants to improve compliance with an evidence-based sepsis bundle when screening criteria are met in the ED. Which CDS intervention is strongest?","opts":[{"l":"A","c":false,"t":"Passive guideline link in the EHR library"},{"l":"B","c":false,"t":"Monthly email reminder to all clinicians"},{"l":"C","c":true,"t":"Triggered sepsis order set embedded in ED workflow"},{"l":"D","c":false,"t":"Paper poster near the medication room"}],"rat":"CDS is most effective when the right information is embedded in the right point of the clinician&#x27;s workflow — a triggered order set at the moment of screening is the gold standard."},
{"id":"RW-D2-17","domain":1,"cog":"AP","correct":"C","task":"Task 2.6","stem":"A drug-allergy CDS alert fires at medication reconciliation and is routed to the bedside nurse — but it is the prescribing physician who holds the authority and clinical responsibility to modify the order. Which of the Five Rights of CDS was violated?","opts":[{"l":"A","c":false,"t":"Right information"},{"l":"B","c":false,"t":"Right time"},{"l":"C","c":true,"t":"Right person"},{"l":"D","c":false,"t":"Right channel"}],"rat":"The Right Person means the alert must reach the clinician who has the ability and authority to act on it, not just any available user in the workflow."},
{"id":"RW-D2-33","domain":1,"cog":"AP","correct":"B","task":"Task 2.6","stem":"A hospital&#x27;s CDS committee is reviewing a drug interaction alert for a commonly co-prescribed combination. They decide to keep the alert but change it from a hard-stop (must acknowledge before proceeding) to a soft-stop (informational, dismissible). The PRIMARY goal of this change is to:","opts":[{"l":"A","c":false,"t":"Eliminate the alert entirely to reduce click burden"},{"l":"B","c":true,"t":"Reduce alert fatigue while preserving clinical awareness for a real but manageable interaction"},{"l":"C","c":false,"t":"Transfer accountability for the interaction to the pharmacist"},{"l":"D","c":false,"t":"Meet regulatory requirements for the specific drug combination"}],"rat":"Tiered alerting uses hard-stops only for highest-severity interactions; soft-stops inform without blocking workflow, reducing fatigue while maintaining clinical relevance."},
{"id":"RW-D2-34","domain":1,"cog":"AN","correct":"B","task":"Task 2.6","stem":"A hospital&#x27;s CDS governance committee is chartered with reviewing all clinical alerts quarterly. A physician representative argues that a fall-risk assessment reminder should apply only to patients 65 and older, not all adult patients. Which governance action is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Dismiss the suggestion because the current alert covers more patients"},{"l":"B","c":true,"t":"Evaluate the evidence for age-based targeting and update the alert logic if the evidence supports it"},{"l":"C","c":false,"t":"Add more fall-risk alerts across all patient populations"},{"l":"D","c":false,"t":"Escalate the question to the vendor for a configuration change without committee review"}],"rat":"CDS governance committees use clinical evidence and override data to tune alert logic. Evidence-based refinement improves clinical relevance and reduces unnecessary alerts."},
{"id":"RW-D2-35","domain":1,"cog":"AN","correct":"B","task":"Task 2.6","stem":"After implementing 12 new CDS alerts in the EHR, the informatics team finds total alert volume increased 40% and physician satisfaction with CDS dropped significantly. The MOST appropriate immediate governance action is:","opts":[{"l":"A","c":false,"t":"Remove all 12 new alerts immediately"},{"l":"B","c":true,"t":"Audit override rates for each new alert and retire or modify those with low clinical value"},{"l":"C","c":false,"t":"Require physicians to document detailed override reasons for every alert dismissed"},{"l":"D","c":false,"t":"Convert all new alerts to hard-stops to force acknowledgment"}],"rat":"Alert governance requires data-driven evaluation. The override rate audit identifies which alerts are adding value and which are contributing to fatigue, guiding targeted optimization."},
{"id":"RW-D2-41","domain":1,"cog":"AP","correct":"C","task":"Task 2.1","stem":"An EHR documentation template requires nurses to assess respiratory rate, oxygen saturation, breath sounds, and use of accessory muscles. Which body system does this assessment map to for documentation and coding purposes?","opts":[{"l":"A","c":false,"t":"Cardiovascular"},{"l":"B","c":false,"t":"Gastrointestinal"},{"l":"C","c":true,"t":"Respiratory"},{"l":"D","c":false,"t":"Neurological"}],"rat":"Respiratory rate, oxygen saturation, breath sounds, and accessory muscle use are all components of the respiratory system assessment — relevant to EHR documentation routing, problem list coding, and clinical decision support logic."},
{"id":"RW-D2-42","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A hospital&#x27;s coding team assigns a code for a patient diagnosed with Type 2 diabetes mellitus with diabetic chronic kidney disease, Stage 3. Which code set is used for this diagnosis — both for inpatient and outpatient records?","opts":[{"l":"A","c":false,"t":"ICD-10-PCS"},{"l":"B","c":false,"t":"CPT"},{"l":"C","c":true,"t":"ICD-10-CM"},{"l":"D","c":false,"t":"HCPCS Level II"}],"rat":"ICD-10-CM is used for diagnosis coding across all care settings (inpatient, outpatient, physician offices). ICD-10-PCS codes only inpatient procedures — not diagnoses."},
{"id":"RW-D2-43","domain":1,"cog":"RE","correct":"B","task":"Task 2.2","stem":"A payer&#x27;s claims system validates that a claim was submitted by a licensed provider using the correct 10-digit standard identifier required for all HIPAA-covered transactions. This identifier is called:","opts":[{"l":"A","c":false,"t":"UPIN (Unique Physician Identification Number)"},{"l":"B","c":true,"t":"NPI (National Provider Identifier)"},{"l":"C","c":false,"t":"DEA registration number"},{"l":"D","c":false,"t":"State medical license number"}],"rat":"The NPI is the HIPAA-required standard identifier for all healthcare providers — individuals and organizations — for all HIPAA-covered electronic transactions."},
{"id":"RW-D2-44","domain":1,"cog":"AN","correct":"C","task":"Task 2.2","stem":"Hospital A sends a FHIR message with a lab result where &quot;sodium&quot; is encoded as LOINC code 2951-2. Hospital B&#x27;s system receives the data, correctly interprets &quot;sodium — serum&quot; from the LOINC code, and displays the result in the correct clinical field. This exchange demonstrates:","opts":[{"l":"A","c":false,"t":"Foundational interoperability — data can be received but not interpreted"},{"l":"B","c":false,"t":"Structural interoperability — data follows a common message format"},{"l":"C","c":true,"t":"Semantic interoperability — shared meaning via common clinical terminology"},{"l":"D","c":false,"t":"Organizational interoperability — governance alignment only"}],"rat":"Semantic interoperability means systems share not just format but meaning — enabled by standard terminologies (LOINC, SNOMED CT, RxNorm). Both systems understand what &quot;LOINC 2951-2&quot; represents clinically."},
{"id":"RW-D2-45","domain":1,"cog":"AP","correct":"B","task":"Task 2.2, 1.A.2","stem":"A hospital&#x27;s EHR generates a structured document at patient discharge containing the problem list, medications, allergies, lab results, and follow-up plan — formatted for transmission to the receiving care team. This document type is called:","opts":[{"l":"A","c":false,"t":"HL7 v2.x ADT message"},{"l":"B","c":true,"t":"C-CDA Transition of Care document"},{"l":"C","c":false,"t":"FHIR Observation resource"},{"l":"D","c":false,"t":"DICOM Structured Report"}],"rat":"The C-CDA Transition of Care / Referral Note is the ONC-required structured document format for exchanging clinical summaries at care transitions — the current standard for Promoting Interoperability."},
{"id":"RW-D2-46","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A hospital&#x27;s inpatient reimbursement for a pneumonia admission is determined by grouping the patient&#x27;s principal diagnosis, secondary diagnoses, procedures, and discharge status into a single fixed-payment category. This Medicare payment classification system is:","opts":[{"l":"A","c":false,"t":"CPT coding"},{"l":"B","c":false,"t":"LOINC terminology mapping"},{"l":"C","c":true,"t":"DRG (Diagnosis-Related Group)"},{"l":"D","c":false,"t":"HCPCS Level II"}],"rat":"DRGs group inpatient discharges by clinical complexity and expected resource use, generating a fixed payment rate per discharge under Medicare&#x27;s inpatient prospective payment system (IPPS)."},
{"id":"RW-D2-47","domain":1,"cog":"AP","correct":"B","task":"Task 2.2, 1.B.1","stem":"A health system with 8 hospitals generates a unique patient ID at each facility, resulting in 8 different IDs for the same patient across the system. Which enterprise-wide solution matches patient identities across all facilities?","opts":[{"l":"A","c":false,"t":"MPI (Master Patient Index) — single-facility patient identity"},{"l":"B","c":true,"t":"EMPI (Enterprise Master Patient Index)"},{"l":"C","c":false,"t":"ADT system"},{"l":"D","c":false,"t":"Data warehouse"}],"rat":"An EMPI extends the MPI concept across multiple facilities, using probabilistic or deterministic matching algorithms to link records belonging to the same patient across different systems and sites."},
{"id":"RW-D2-48","domain":1,"cog":"AP","correct":"C","task":"Task 2.3","stem":"A hospital discharged 400 patients in October with a total of 2,000 inpatient days. What is the Average Length of Stay (ALOS)?","opts":[{"l":"A","c":false,"t":"400 days"},{"l":"B","c":false,"t":"4 days"},{"l":"C","c":true,"t":"5 days"},{"l":"D","c":false,"t":"2,000 days"}],"rat":"ALOS = total inpatient days ÷ total discharges = 2,000 ÷ 400 = 5 days. ALOS benchmarking is critical for operational efficiency and CMS value-based purchasing comparisons."},
{"id":"RW-D2-49","domain":1,"cog":"AP","correct":"B","task":"Task 2.3","stem":"A hospital&#x27;s lab department measures the time from when a blood culture is ordered in the EHR to when the finalized result is available to the ordering physician. This measurement is called:","opts":[{"l":"A","c":false,"t":"Average Daily Census"},{"l":"B","c":true,"t":"Turnaround time (TAT)"},{"l":"C","c":false,"t":"Case Mix Index"},{"l":"D","c":false,"t":"30-day readmission rate"}],"rat":"Turnaround time (TAT) measures the elapsed time from order to result or service delivery — a key operational performance metric for lab, radiology, and pharmacy departments."},
{"id":"RW-D2-50","domain":1,"cog":"AP","correct":"B","task":"Task 2.3","stem":"A medical-surgical unit had 3 patient falls last month. The unit recorded 600 patient days in that period. What is the falls rate per 1,000 patient days?","opts":[{"l":"A","c":false,"t":"0.5"},{"l":"B","c":true,"t":"5"},{"l":"C","c":false,"t":"50"},{"l":"D","c":false,"t":"200"}],"rat":"Falls rate = (falls ÷ patient days) × 1,000 = (3 ÷ 600) × 1,000 = 5 per 1,000 patient days. This standard formula applies to falls, CLABSIs, CAUTIs, and other event-rate metrics."},
{"id":"RW-D2-51","domain":1,"cog":"AN","correct":"B","task":"Task 2.3","stem":"A hospital&#x27;s revenue cycle team reports that Days in Accounts Receivable (A/R) increased from 42 to 58 days over the past quarter. Which of the following is the MOST likely operational consequence?","opts":[{"l":"A","c":false,"t":"The hospital collected more revenue faster than expected"},{"l":"B","c":true,"t":"Cash flow is delayed — the hospital waits longer to receive payment for services already rendered"},{"l":"C","c":false,"t":"The hospital is treating a more complex patient mix"},{"l":"D","c":false,"t":"More patients are being readmitted, increasing revenue"}],"rat":"Days in A/R measures how long it takes to collect payment after service. An increase from 42 to 58 days means slower collections — a cash flow concern requiring revenue cycle investigation."},
{"id":"RW-D2-52","domain":1,"cog":"AN","correct":"B","task":"Task 2.3","stem":"A hospital&#x27;s payer mix shifts from 40% Medicare / 40% commercial / 20% Medicaid to 55% Medicare / 30% commercial / 15% Medicaid. All else being equal, what is the MOST likely financial impact?","opts":[{"l":"A","c":false,"t":"Revenue will increase because Medicare pays the fastest"},{"l":"B","c":true,"t":"Revenue per case will likely decrease because Medicare typically reimburses at lower rates than commercial payers"},{"l":"C","c":false,"t":"Revenue will be unaffected because total volume is unchanged"},{"l":"D","c":false,"t":"Revenue will increase because Medicaid rates have been reduced"}],"rat":"Commercial payers generally reimburse at higher rates than Medicare or Medicaid. A shift toward higher Medicare share and lower commercial share typically reduces average revenue per case."},
{"id":"RW-D2-53","domain":1,"cog":"AP","correct":"C","task":"Task 2.4, 2.6","stem":"After CPOE implementation, the system alerts a hospitalist that an ordered gentamicin dose exceeds the weight-based maximum safe dose for a 12-year-old pediatric patient. Which EHR system functionality generates this safety check?","opts":[{"l":"A","c":false,"t":"Charge capture validation"},{"l":"B","c":false,"t":"Drug-allergy interaction checking"},{"l":"C","c":true,"t":"Dose range checking / dose calculation CDS"},{"l":"D","c":false,"t":"eMAR scanning requirement"}],"rat":"Dose range checking validates that ordered doses fall within safe clinical ranges — weight-based for pediatric patients. This is distinct from drug-allergy (allergy cross-reference) and drug-drug (interaction) alerts."},
{"id":"RW-D2-54","domain":1,"cog":"AP","correct":"B","task":"Task 2.4","stem":"A hospitalist types &quot;.hpi&quot; into the EHR&#x27;s note editor and the system automatically expands it into a pre-built History of Present Illness template with common clinical prompts. This feature is called:","opts":[{"l":"A","c":false,"t":"Voice recognition dictation"},{"l":"B","c":true,"t":"Smart text / dot phrase"},{"l":"C","c":false,"t":"Structured order entry"},{"l":"D","c":false,"t":"At-the-Elbow documentation support"}],"rat":"Smart text (dot phrases, auto-text) are reusable, personalized text templates that expand on a keyboard shortcut — accelerating clinical documentation without sacrificing structure or completeness."},
{"id":"RW-D2-55","domain":1,"cog":"AP","correct":"C","task":"Task 2.4","stem":"A radiologist dictates findings aloud while reviewing CT images, and the spoken words are converted to text in real time within the PACS-linked reporting system — no keyboard input required. This capability is:","opts":[{"l":"A","c":false,"t":"Smart text expansion"},{"l":"B","c":false,"t":"NLP-based retrospective analytics"},{"l":"C","c":true,"t":"Voice recognition documentation"},{"l":"D","c":false,"t":"Structured data entry template"}],"rat":"Voice recognition (e.g., Dragon Medical) converts speech to text in real time, enabling hands-free documentation. NLP is a separate technology used to extract meaning from existing text — not real-time transcription."},
{"id":"RW-D2-56","domain":1,"cog":"AN","correct":"B","task":"Task 2.4","stem":"During a planned EHR maintenance downtime, an ICU nurse needs to document hourly vital signs and administer medications. Which resource BEST guides clinical care during this period?","opts":[{"l":"A","c":false,"t":"The EHR&#x27;s training environment replica"},{"l":"B","c":true,"t":"Printed downtime forms and a manual medication administration record"},{"l":"C","c":false,"t":"Text messages to the attending physician for each documentation entry"},{"l":"D","c":false,"t":"Delaying all documentation until the system is restored"}],"rat":"Downtime procedures include pre-printed paper forms (vital sign flowsheets, paper MAR) that allow safe clinical care to continue during planned or unplanned EHR outages. Delaying documentation is unsafe and unacceptable."},
{"id":"RW-D2-57","domain":1,"cog":"RE","correct":"C","task":"Task 2.5","stem":"A hospital publishes a monthly report showing the total number of inpatient admissions by DRG category for the previous month. This report represents which analytics maturity level?","opts":[{"l":"A","c":false,"t":"Diagnostic — it explains why admissions occurred"},{"l":"B","c":false,"t":"Predictive — it forecasts future admissions"},{"l":"C","c":true,"t":"Descriptive"},{"l":"D","c":false,"t":"Prescriptive"}],"rat":"Descriptive analytics answers &quot;what happened&quot; — summarizing historical data in reports and dashboards. No causal analysis or prediction is involved. It is the foundation on which higher analytics maturity levels build."},
{"id":"RW-D2-58","domain":1,"cog":"AP","correct":"C","task":"Task 2.5","stem":"An infection control team wants to visualize the geographic distribution of HAI rates across 30 nursing units — showing which floors and wings have the highest infection concentration at a glance. The MOST effective visualization is:","opts":[{"l":"A","c":false,"t":"Run chart tracking infection rates by month"},{"l":"B","c":false,"t":"Bar chart comparing infection rates alphabetically by unit name"},{"l":"C","c":true,"t":"Heat map overlaid on a floor plan"},{"l":"D","c":false,"t":"Scatter plot of infection rate versus hand hygiene compliance"}],"rat":"Heat maps display intensity patterns across two dimensions (floor geography and infection rate), making geographic clustering immediately visible — ideal for spatial pattern analysis."},
{"id":"RW-D2-59","domain":1,"cog":"AP","correct":"B","task":"Task 2.5","stem":"A hospital&#x27;s operational command center displays current ED wait time, inpatient bed occupancy rate, ICU census, and OR utilization — all updated in near-real time. This display is designed primarily to:","opts":[{"l":"A","c":false,"t":"Predict next quarter&#x27;s patient volume"},{"l":"B","c":true,"t":"Support real-time operational decision-making by displaying multiple KPIs simultaneously"},{"l":"C","c":false,"t":"Replace the electronic medical record for documentation"},{"l":"D","c":false,"t":"Generate automated patient discharge orders"}],"rat":"Dashboards aggregate multiple KPIs in a single view for operational monitoring and rapid decision-making — the primary use case is situational awareness, not prediction or documentation."},
{"id":"RW-D2-60","domain":1,"cog":"AN","correct":"B","task":"Task 2.5","stem":"A quality analyst reviewing monthly readmission data notices that one hospitalist&#x27;s patients have a 30-day readmission rate of 28% — significantly higher than the department average of 14% and the national benchmark of 12%. This data point warrants:","opts":[{"l":"A","c":false,"t":"No action — it is within the expected range of normal variation"},{"l":"B","c":true,"t":"Root cause investigation before drawing conclusions about care quality"},{"l":"C","c":false,"t":"Immediate disciplinary action against the hospitalist"},{"l":"D","c":false,"t":"Removing the hospitalist from the analysis to prevent skewing the average"}],"rat":"A statistical outlier signals a need for investigation — not immediate judgment. The elevated rate could reflect patient complexity, documentation issues, or a true care quality concern. Root cause analysis must precede action."},
{"id":"RW-D2-61","domain":1,"cog":"AP","correct":"B","task":"Task 2.5","stem":"A study reports a new discharge planning process reduced 30-day readmissions by 15% (95% CI: 8%–22%). A committee member asks what the confidence interval means. The BEST explanation is:","opts":[{"l":"A","c":false,"t":"The study is 95% certain the intervention will work in all hospitals"},{"l":"B","c":true,"t":"We are 95% confident the true population effect falls between an 8% and 22% reduction"},{"l":"C","c":false,"t":"The intervention only worked in 95% of study patients"},{"l":"D","c":false,"t":"The confidence interval shows the range of the p-value"}],"rat":"A 95% confidence interval means if the study were repeated many times, 95% of the resulting intervals would contain the true population effect. A narrower CI indicates a more precise estimate."},
{"id":"RW-D2-62","domain":1,"cog":"AN","correct":"C","task":"Task 2.5","stem":"A health system trains a machine learning model on 5 years of historical patient data — demographics, diagnoses, lab trends, medications, and prior utilizations — to identify patients most likely to be hospitalized within the next 90 days. This model represents:","opts":[{"l":"A","c":false,"t":"Descriptive analytics — summarizing historical hospitalization patterns"},{"l":"B","c":false,"t":"Diagnostic analytics — explaining why patients were previously hospitalized"},{"l":"C","c":true,"t":"Predictive analytics using machine learning"},{"l":"D","c":false,"t":"Prescriptive analytics — automatically scheduling care management calls"}],"rat":"ML models that use historical data to forecast future outcomes (hospitalization risk) are predictive analytics. If the model also automatically routes patients to a care queue, that would be prescriptive."},
{"id":"RW-D2-63","domain":1,"cog":"RE","correct":"B","task":"Task 2.6","stem":"A CDS alert fires because a patient&#x27;s warfarin order may interact with newly prescribed aspirin, increasing bleeding risk. A separate alert fires because the patient has a sulfa allergy and was prescribed trimethoprim-sulfamethoxazole. These are examples of:","opts":[{"l":"A","c":false,"t":"Both are drug-allergy alerts"},{"l":"B","c":true,"t":"Drug-drug interaction alert and drug-allergy alert, respectively"},{"l":"C","c":false,"t":"Both are dose range checking alerts"},{"l":"D","c":false,"t":"Drug-allergy alert and drug-drug interaction alert, respectively"}],"rat":"Drug-drug interaction (DDI) alerts check hazardous combinations of medications; drug-allergy alerts check whether an ordered medication matches a documented patient allergy. Both are CDS mechanisms but serve distinct safety functions."},
{"id":"RW-D2-64","domain":1,"cog":"AP","correct":"C","task":"Task 2.6","stem":"An ICU&#x27;s EHR automatically calculates a National Early Warning Score (NEWS) every hour by aggregating vital sign data. When the score exceeds 7, it alerts the bedside nurse and attending physician. This CDS function is BEST described as:","opts":[{"l":"A","c":false,"t":"A drug-drug interaction alert"},{"l":"B","c":false,"t":"A dose range checking alert"},{"l":"C","c":true,"t":"An early warning score / patient deterioration alert"},{"l":"D","c":false,"t":"An evidence-based order set trigger"}],"rat":"Early Warning Scores (NEWS, MEWS, SEWS) aggregate physiological parameters to detect patient deterioration risk — triggering escalation alerts before clinical collapse occurs."},
{"id":"RW-D2-65","domain":1,"cog":"AP","correct":"C","task":"Task 2.6","stem":"While a cardiologist is ordering a medication, a small icon appears next to the drug name. Clicking it opens a drug monograph and contraindication list from a clinical knowledge database — without leaving the ordering workflow. Which type of CDS intervention is this?","opts":[{"l":"A","c":false,"t":"Hard-stop alert requiring acknowledgment"},{"l":"B","c":false,"t":"Soft-stop reminder notification"},{"l":"C","c":true,"t":"Infobutton (in-context reference link)"},{"l":"D","c":false,"t":"Evidence-based order set"}],"rat":"An infobutton is a context-sensitive link to clinical reference information (drug monographs, guidelines) embedded at the point of care — the Right Format CDS intervention for &quot;just-in-time&quot; knowledge access without interrupting workflow."},
{"id":"RW-D2-66","domain":1,"cog":"AN","correct":"C","task":"Task 2.6","stem":"A CDS alert fires when a nephrologist orders metformin 1,000 mg daily for a diabetic patient whose eGFR is 28 — metformin is contraindicated below eGFR 30 due to lactic acidosis risk. According to the Five Rights of CDS, this alert satisfies:","opts":[{"l":"A","c":false,"t":"Right person only — it was delivered to the prescribing physician"},{"l":"B","c":false,"t":"Right information only — the clinical content is accurate"},{"l":"C","c":true,"t":"All five rights: right information, right person, right format, right channel, right time"},{"l":"D","c":false,"t":"Right channel only — it appeared within the EHR ordering workflow"}],"rat":"This alert delivers evidence-based actionable content (right information) to the prescribing nephrologist (right person) as a pop-up (right format) in the EHR (right channel) at the moment of order entry (right time) — all five CDS rights are satisfied."},
{"id":"RW-D2-67","domain":1,"cog":"AP","correct":"B","task":"Task 2.6","stem":"A CDS alert correctly fires for a prescribing physician regarding a potential drug interaction. However, the same alert is also configured to send a daily email digest of all overridden interactions to the quality department — 24 hours after prescriptions are signed. The quality department email fails which of the Five Rights of CDS?","opts":[{"l":"A","c":false,"t":"Right information"},{"l":"B","c":true,"t":"Right person and right time"},{"l":"C","c":false,"t":"Right format"},{"l":"D","c":false,"t":"Right channel"}],"rat":"The quality department email fails Right Person (the quality team cannot modify the order) and Right Time (24 hours later is not actionable at the point of care). CDS must reach those who can act, when they can act."},
{"id":"RW-D2-68","domain":1,"cog":"AN","correct":"C","task":"Task 2.6","stem":"A hospital&#x27;s CDS governance committee reviews a drug interaction alert that has been active for 3 years. The clinical guideline it was based on has been updated — the interaction is now classified as clinically insignificant by current evidence. The alert&#x27;s override rate is 97%. What should the committee do?","opts":[{"l":"A","c":false,"t":"Keep the alert unchanged because it has been in production for 3 years"},{"l":"B","c":false,"t":"Convert it to a hard-stop to reduce the 97% override rate"},{"l":"C","c":true,"t":"Retire or significantly downgrade the alert based on updated clinical evidence and high override rate"},{"l":"D","c":false,"t":"Add the alert to all order sets for greater visibility"}],"rat":"A 97% override rate combined with outdated clinical evidence is definitive justification for alert retirement or downgrade. CDS governance exists precisely to review and retire alerts that no longer reflect current evidence or add clinical value."},
{"id":"RW-D2-69","domain":1,"cog":"AP","correct":"B","task":"Task 2.2","stem":"A CDI specialist reviews the chart of a hospitalized patient whose documentation reads only &quot;heart failure.&quot; Clinical evidence in the record supports acute-on-chronic systolic heart failure, NYHA Class III — a higher-weighted DRG. The specialist queries the attending physician for a more specific diagnosis before the patient is discharged. This type of CDI query is called:","opts":[{"l":"A","c":false,"t":"Retrospective query — performed after the patient is discharged"},{"l":"B","c":true,"t":"Concurrent query — performed during the hospitalization before discharge"},{"l":"C","c":false,"t":"Post-discharge audit — performed by the compliance department"},{"l":"D","c":false,"t":"DRG validation query — performed by the payer during claims review"}],"rat":"Concurrent CDI queries are performed during the hospitalization, allowing the physician to clarify documentation specificity before discharge. This enables accurate DRG assignment in real time, directly impacting reimbursement and quality reporting."},
{"id":"RW-D2-70","domain":1,"cog":"AN","correct":"C","task":"Task 2.2, 2.3","stem":"A CDI specialist&#x27;s concurrent query results in the attending physician updating documentation from &quot;pneumonia&quot; to &quot;aspiration pneumonia&quot; — supported by clinical evidence in the record. Which of the following BEST describes the financial impact of this documentation update?","opts":[{"l":"A","c":false,"t":"The Case Mix Index will decrease because the diagnosis is now more specific"},{"l":"B","c":false,"t":"Reimbursement will decrease because aspiration pneumonia requires more resources"},{"l":"C","c":true,"t":"Reimbursement will increase because aspiration pneumonia maps to a higher-weighted DRG than unspecified pneumonia"},{"l":"D","c":false,"t":"The DRG assignment is unchanged because the patient&#x27;s discharge status did not change"}],"rat":"More specific, clinically supported documentation maps to a higher-weighted DRG, increasing appropriate reimbursement. A higher DRG weight raises the Case Mix Index. CDI programs improve documentation specificity to ensure reimbursement accurately reflects clinical complexity — not to upcode unsupported claims."},
{"id":"RW-D2-71","domain":1,"cog":"AP","correct":"B","task":"Task 2.2","stem":"A hospital implements software that reads physician progress notes and discharge summaries, then automatically proposes ICD-10-CM diagnosis codes and ICD-10-PCS procedure codes to the coding team for review and validation. This technology is:","opts":[{"l":"A","c":false,"t":"CDI concurrent querying — the system queries physicians in real time"},{"l":"B","c":true,"t":"Computer-Assisted Coding (CAC) — NLP proposes codes for coder review and validation"},{"l":"C","c":false,"t":"Automated DRG grouping — the system assigns final codes without human review"},{"l":"D","c":false,"t":"Registry population — the system feeds a disease registry from clinical text"}],"rat":"Computer-Assisted Coding (CAC) uses NLP to extract clinical concepts from free text and propose ICD-10-CM, ICD-10-PCS, and CPT codes. Coders review, accept, modify, or reject proposed codes — CAC increases coding speed and consistency but does not replace coder judgment."},
{"id":"RW-D2-72","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A nursing informatics team wants to standardize nursing diagnoses across all EHR documentation templates to enable analytics and outcome measurement. Which terminology standard provides standardized, validated nursing diagnosis labels such as &quot;Risk for Falls&quot; and &quot;Impaired Gas Exchange&quot;?","opts":[{"l":"A","c":false,"t":"LOINC — standardizes lab tests and clinical observations"},{"l":"B","c":false,"t":"SNOMED CT — standardizes clinical concepts in EHR documentation"},{"l":"C","c":true,"t":"NANDA-I — North American Nursing Diagnosis Association International"},{"l":"D","c":false,"t":"ICD-10-CM — used for billable diagnosis coding in all care settings"}],"rat":"NANDA-I provides standardized nursing diagnosis labels and definitions used in EHR nursing documentation. LOINC = lab observations; SNOMED CT = broader clinical concepts including physician diagnoses and findings; ICD-10-CM = billable diagnosis codes for claims."},
{"id":"RW-D2-73","domain":1,"cog":"AP","correct":"B","task":"Task 2.2","stem":"A nursing informatics committee selects NANDA-I as the standard for nursing diagnoses in the new EHR. They also need standards for nursing INTERVENTIONS and measurable nursing OUTCOMES. Which two standards complete this triad?","opts":[{"l":"A","c":false,"t":"LOINC (interventions) and RxNorm (outcomes)"},{"l":"B","c":true,"t":"NIC — Nursing Interventions Classification (interventions) and NOC — Nursing Outcomes Classification (outcomes)"},{"l":"C","c":false,"t":"CPT (interventions) and HCPCS Level II (outcomes)"},{"l":"D","c":false,"t":"SNOMED CT (interventions) and NDC (outcomes)"}],"rat":"The nursing informatics triad is NANDA-I (standardized diagnoses), NIC — Nursing Interventions Classification (standardized intervention labels and definitions), and NOC — Nursing Outcomes Classification (standardized, measurable outcomes). Together they enable evidence-based nursing documentation, analytics, and outcomes measurement."},
{"id":"RW-D2-74","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A hospital submits data quarterly to a national database that tracks outcomes for all coronary artery bypass graft (CABG) surgeries — including mortality, complications, and 30-day readmission rates — compared against peer institutions. This external database is BEST described as:","opts":[{"l":"A","c":false,"t":"The hospital&#x27;s internal operational data warehouse"},{"l":"B","c":false,"t":"A state public health immunization registry"},{"l":"C","c":true,"t":"A clinical quality registry for benchmarking condition-specific outcomes"},{"l":"D","c":false,"t":"A revenue cycle claims database for payer adjudication"}],"rat":"Clinical quality registries (e.g., STS Database for cardiac surgery, NSQIP for surgical outcomes) aggregate condition-specific outcome data across institutions, enabling comparative benchmarking, quality measurement, and performance improvement. They are distinct from internal data warehouses or public health registries."},
{"id":"RW-D2-75","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A rural clinic&#x27;s EHR receives lab results electronically from the regional hospital laboratory system. However, the receiving system stores the result as a non-searchable PDF attachment — clinical staff must read the PDF manually and cannot filter or trend lab values in the EHR. This exchange represents:","opts":[{"l":"A","c":false,"t":"Semantic interoperability — data is received and interpreted with shared meaning"},{"l":"B","c":false,"t":"Structural interoperability — data follows a common message format"},{"l":"C","c":true,"t":"Foundational interoperability — data is transported but not interpretable by the receiving system"},{"l":"D","c":false,"t":"Organizational interoperability — a policy and governance issue"}],"rat":"Foundational interoperability enables data transport (the file arrives), but the receiving system cannot interpret or process the content programmatically — it is an opaque document. Structural requires common format; semantic requires shared meaning via standard terminologies. Foundational is the lowest level."},
{"id":"RW-D2-76","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A hospital&#x27;s ADT system sends a message to downstream billing, bed management, and care coordination systems each time a patient is admitted, transferred, or discharged — automatically triggering workflows without manual data entry. Which messaging standard is being used?","opts":[{"l":"A","c":false,"t":"FHIR RESTful API — the current ONC-mandated patient-facing standard"},{"l":"B","c":false,"t":"C-CDA Transition of Care document — the structured discharge summary format"},{"l":"C","c":true,"t":"HL7 v2.x ADT (Admit-Discharge-Transfer) message"},{"l":"D","c":false,"t":"DICOM SR (Structured Report) — used for radiology reporting"}],"rat":"HL7 v2.x ADT messages (A01=admit, A03=discharge, A02=transfer, A08=update) are the most widely deployed HL7 messages in healthcare, driving downstream system workflow triggers for billing, bed management, and care coordination. They are distinct from FHIR, which is used for patient-facing API access."},
{"id":"RW-D2-77","domain":1,"cog":"AP","correct":"C","task":"Task 2.2","stem":"A patient-facing app developer wants to query a hospital EHR to retrieve a patient&#x27;s medication list, allergies, and recent lab results using a standard web-based API — required by the 21st Century Cures Act and ONC regulations. The mandated standard for this type of app-based data access is:","opts":[{"l":"A","c":false,"t":"HL7 v2.x ADT messaging — used for admit/discharge/transfer workflows"},{"l":"B","c":false,"t":"C-CDA document exchange — used for structured care transition summaries"},{"l":"C","c":true,"t":"HL7 FHIR R4 RESTful API"},{"l":"D","c":false,"t":"DICOM — used for medical imaging exchange"}],"rat":"HL7 FHIR (Fast Healthcare Interoperability Resources) R4 is mandated by ONC under the 21st Century Cures Act for patient-facing app data access. FHIR uses RESTful APIs and JSON/XML resources, enabling standardized queries from apps, payers, and patients. EHR vendors must expose FHIR APIs for patient data access."},
{"id":"RW-D2-78","domain":1,"cog":"AN","correct":"C","task":"Task 2.2","stem":"A patient downloads an app, links it to their hospital EHR and personal fitness tracker, and creates a record containing their medications, allergies, lab results, immunizations, and daily activity data — all stored outside the hospital&#x27;s system with the patient controlling who can access it. This is BEST described as:","opts":[{"l":"A","c":false,"t":"An EHR — maintained by the healthcare organization and shared across providers"},{"l":"B","c":false,"t":"An EMR — maintained by a single provider for internal clinical documentation"},{"l":"C","c":true,"t":"A PHR (Personal Health Record) — patient-owned and patient-controlled"},{"l":"D","c":false,"t":"A health information exchange — a regional network for provider-to-provider sharing"}],"rat":"A PHR is patient-owned, patient-controlled, and can aggregate health data from multiple sources (EHR, wearables, self-reported). The patient determines what is shared and with whom. EHRs are provider-maintained and organization-controlled; EMRs are for single-provider internal use."},
{"id":"RW-D2-79","domain":1,"cog":"AP","correct":"B","task":"Task 2.5","stem":"A quality analyst reviews a control chart tracking monthly hand hygiene compliance over 18 months. All data points fall within the upper and lower control limits, scattered above and below the centerline without any consistent pattern or trend. This chart MOST likely indicates:","opts":[{"l":"A","c":false,"t":"Special cause variation — an urgent investigation into the process is warranted"},{"l":"B","c":true,"t":"A stable process in statistical control, exhibiting only common cause (normal) variation"},{"l":"C","c":false,"t":"Sustained improvement from a recent quality intervention"},{"l":"D","c":false,"t":"A data collection error — the control limits should be recalculated"}],"rat":"When all points fall within control limits with no non-random patterns, the process is in statistical control — exhibiting only common cause (inherent, normal) variation. This does not mean performance is acceptable, but it means the process is stable and predictable. No special cause intervention is warranted."},
{"id":"RW-D2-80","domain":1,"cog":"AN","correct":"B","task":"Task 2.5","stem":"A control chart tracking monthly CLABSI rates shows 9 consecutive data points all above the centerline (mean), though all remain within the upper control limit. A staff nurse argues this is normal variation since no point exceeds the control limit. The BEST response is:","opts":[{"l":"A","c":false,"t":"Agree — control chart rules only apply when points exceed the upper or lower control limit"},{"l":"B","c":true,"t":"Disagree — eight or more consecutive points on one side of the centerline is a special cause signal requiring investigation, regardless of whether points cross the control limit"},{"l":"C","c":false,"t":"Remove the nine months from the chart and recalculate the centerline"},{"l":"D","c":false,"t":"Switch to a run chart, which does not use control limits and is easier to interpret"}],"rat":"Statistical process control rules define special cause signals beyond just points outside control limits. Eight or more consecutive points on the same side of the centerline indicates a non-random shift — a special cause signal that warrants investigation even if no point crosses a control limit."},
{"id":"RW-D2-81","domain":1,"cog":"AN","correct":"B","task":"Task 2.5","stem":"An NLP system extracts diagnoses from ED notes to auto-populate a sepsis registry. A note reads: &quot;Patient denies fever. No evidence of infection. Blood cultures ordered to rule out sepsis.&quot; If the NLP system lacks negation detection, which error is MOST likely?","opts":[{"l":"A","c":false,"t":"The system will fail to extract the blood culture order entirely"},{"l":"B","c":true,"t":"The system will incorrectly record fever, infection, and sepsis as confirmed diagnoses in the registry"},{"l":"C","c":false,"t":"The system will generate a duplicate registry entry for this patient"},{"l":"D","c":false,"t":"The system will route the note to the wrong disease registry"}],"rat":"Without negation detection, NLP extracts &quot;fever,&quot; &quot;infection,&quot; and &quot;sepsis&quot; as positive findings — even when the text explicitly negates them. Negation detection is a critical NLP component that distinguishes confirmed findings from denied, ruled-out, or hypothetical conditions."},
{"id":"RW-D2-82","domain":1,"cog":"AP","correct":"C","task":"Task 2.5","stem":"A quality team wants to understand the distribution of inpatient lengths of stay — specifically whether most patients leave within 3 days or whether a small number of outliers with very long stays are driving the average upward. Which visualization is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Scatter plot — to correlate LOS with a second variable such as diagnosis"},{"l":"B","c":false,"t":"Run chart — to track monthly average LOS trends over time"},{"l":"C","c":true,"t":"Histogram — to show the frequency distribution of individual LOS values"},{"l":"D","c":false,"t":"Pie chart — to show the proportion of LOS categories"}],"rat":"A histogram displays the frequency distribution of a single continuous variable, revealing the shape, spread, and outlier pattern of the data. It is the correct choice when the question is &quot;how are LOS values distributed?&quot; — not how they trend over time (run chart) or correlate with another variable (scatter plot)."},
{"id":"RW-D2-83","domain":1,"cog":"AN","correct":"C","task":"Task 2.2","stem":"Two health systems exchange patient medication data using HL7 FHIR — both transmit and receive data in the correct FHIR MedicationRequest resource format. However, one system uses proprietary internal drug codes and the other uses RxNorm, so neither system can programmatically interpret the other&#x27;s drug names. This exchange represents:","opts":[{"l":"A","c":false,"t":"Semantic interoperability — the format is standardized, which is sufficient"},{"l":"B","c":false,"t":"Foundational interoperability — data cannot be received"},{"l":"C","c":true,"t":"Structural interoperability — common format without shared meaning"},{"l":"D","c":false,"t":"Organizational interoperability — a governance and policy gap"}],"rat":"Structural interoperability means both systems use a common data format and structure (HL7 FHIR), enabling consistent exchange. However, without shared terminologies (RxNorm), neither system can interpret the drug content — this is the semantic gap. Semantic interoperability requires both common structure AND shared meaning via standard terminologies."},
{"id":"RW-D2-84","domain":1,"cog":"AP","correct":"B","task":"Task 2.3, 2.4","stem":"A nurse prepares to administer a medication. The BCMA scanner alerts that the scanned medication barcode does not match the active order. The nurse stops, verifies the mismatch, retrieves the correct medication, and administers it without incident. No patient harm occurred. This event is classified as:","opts":[{"l":"A","c":false,"t":"Adverse drug event — the patient was exposed to a potential harm"},{"l":"B","c":true,"t":"Near-miss — an error was intercepted before reaching the patient"},{"l":"C","c":false,"t":"Sentinel event — requiring root cause analysis and external reporting"},{"l":"D","c":false,"t":"Medication error — because the wrong medication was prepared"}],"rat":"A near-miss (close call, good catch) is an error that was detected and corrected before reaching the patient, resulting in no harm. BCMA is specifically designed to intercept wrong-drug errors at the point of administration — converting potential medication errors into near-misses. Near-miss tracking is a key patient safety metric."},
{"id":"RW-D2-85","domain":1,"cog":"AP","correct":"B","task":"Task 2.6","stem":"An EHR automatically fires an alert when a hospitalist orders a full standard dose of a renally-cleared antibiotic for a patient whose most recent creatinine-based eGFR is 22 mL/min — below the threshold requiring dose reduction. Which CDS type does this alert represent?","opts":[{"l":"A","c":false,"t":"Drug-drug interaction alert — checking a hazardous combination of two medications"},{"l":"B","c":true,"t":"Renal dose adjustment CDS — applying eGFR-based dosing thresholds"},{"l":"C","c":false,"t":"Drug-allergy alert — cross-referencing the medication against documented allergies"},{"l":"D","c":false,"t":"Early warning score — triggered by aggregated vital sign parameters"}],"rat":"eGFR-based dose adjustment alerts are a distinct CDS type that checks whether the ordered dose is appropriate for the patient&#x27;s current renal function. Renally-cleared drugs (vancomycin, gentamicin, metformin, enoxaparin) require dose reduction or avoidance when eGFR falls below defined thresholds — separate from drug-allergy or drug-drug interaction logic."},
{"id":"RW-D2-86","domain":1,"cog":"AN","correct":"B","task":"Task 2.5","stem":"A hospital reports a mean ALOS of 8.4 days. However, analysis reveals that 85% of patients are discharged within 4 days, while a small number of complex patients with 60+ day stays are skewing the average upward significantly. The quality team wants the measure that BEST represents the typical patient&#x27;s experience. Which measure should they use?","opts":[{"l":"A","c":false,"t":"Mean — because it accounts for all patients in the calculation"},{"l":"B","c":true,"t":"Median — because it is resistant to outliers and better represents the typical experience"},{"l":"C","c":false,"t":"Standard deviation — because it measures how spread out LOS values are"},{"l":"D","c":false,"t":"Case Mix Index — because it adjusts for clinical complexity"}],"rat":"The median (middle value when all LOS values are ranked) is not distorted by extreme outliers. When a small number of very long stays skew the mean upward, the median better represents the &quot;typical&quot; patient&#x27;s LOS. The mean overstates the typical experience in right-skewed LOS distributions."},
{"id":"RW-D2-87","domain":1,"cog":"AP","correct":"B","task":"Task 2.3","stem":"An ICU reports 3 central line-associated bloodstream infections (CLABSIs) in a month with 600 total central line-days. What is the CLABSI rate per 1,000 central line-days?","opts":[{"l":"A","c":false,"t":"0.5"},{"l":"B","c":true,"t":"5"},{"l":"C","c":false,"t":"50"},{"l":"D","c":false,"t":"200"}],"rat":"CLABSI rate = (infections ÷ central line-days) × 1,000 = (3 ÷ 600) × 1,000 = 5 per 1,000 central line-days. This standard &quot;per 1,000 device-days&quot; formula also applies to CAUTI (per 1,000 catheter-days) and falls (per 1,000 patient-days), enabling fair comparison across units with different patient volumes."},
{"id":"RW-D2-88","domain":1,"cog":"AN","correct":"D","task":"Task 2.2","stem":"Two competing health systems decide to share patient data for care coordination. Their EHR systems can already exchange HL7 FHIR-formatted data and both use RxNorm for medications and LOINC for labs. The primary remaining barrier is negotiating data governance agreements, patient consent workflows, legal contracts (BAAs), and operational protocols for who can access what data and under what conditions. The work they are doing PRIMARILY addresses:","opts":[{"l":"A","c":false,"t":"Structural interoperability — standardizing data formats"},{"l":"B","c":false,"t":"Semantic interoperability — aligning clinical terminologies"},{"l":"C","c":false,"t":"Foundational interoperability — enabling basic data transport"},{"l":"D","c":true,"t":"Organizational interoperability — aligning policies, governance, trust, and legal agreements"}],"rat":"Organizational interoperability encompasses the governance, policy, legal, and workflow alignment needed to enable actual data sharing — even when the technical and semantic layers are already in place. It is often cited as the most difficult barrier to healthcare interoperability in practice, requiring trust frameworks, consent models, and contractual agreements between organizations."}
];
